//! 폰트 메트릭 데이터 (자동 생성)
//!
//! font-metric-gen 도구로 TTF 파일에서 추출.
//! 수동 편집 금지.

#[derive(Debug)]
pub struct HangulMetric {
    pub cho_groups: u8,
    pub jung_groups: u8,
    pub jong_groups: u8,
    pub cho_map: &'static [u8],
    pub jung_map: &'static [u8],
    pub jong_map: &'static [u8],
    pub widths: &'static [u16],
}

#[derive(Debug)]
pub struct FontMetric {
    pub name: &'static str,
    pub bold: bool,
    pub italic: bool,
    pub em_size: u16,
    pub latin_ranges: &'static [LatinRange],
    pub hangul: Option<&'static HangulMetric>,
}

#[derive(Debug)]
pub struct LatinRange {
    pub start: u32,
    pub end: u32,
    pub widths: &'static [u16],
}

impl FontMetric {
    pub fn get_width(&self, ch: char) -> Option<u16> {
        let code = ch as u32;
        // 한글 음절 (U+AC00~U+D7A3)
        if code >= 0xAC00 && code <= 0xD7A3 {
            if let Some(h) = self.hangul {
                let idx = code - 0xAC00;
                let cho = (idx / (21 * 28)) as usize;
                let jung = ((idx % (21 * 28)) / 28) as usize;
                let jong = (idx % 28) as usize;
                let gi = h.cho_map[cho] as usize
                    * h.jung_groups as usize * h.jong_groups as usize
                    + h.jung_map[jung] as usize * h.jong_groups as usize
                    + h.jong_map[jong] as usize;
                return h.widths.get(gi).copied();
            }
            return None;
        }
        // Latin 및 기타 범위
        for range in self.latin_ranges {
            if code >= range.start && code <= range.end {
                let w = range.widths[(code - range.start) as usize];
                return if w > 0 { Some(w) } else { None };
            }
        }
        None
    }
}

/// find_metric의 반환값: 메트릭 + 폴백 정보
pub struct MetricMatch {
    pub metric: &'static FontMetric,
    /// Bold 요청했으나 Bold 메트릭이 없어 Regular로 폴백됨
    /// → Faux Bold 폭 보정이 필요한 경우 true
    pub bold_fallback: bool,
}

/// 한국어 폰트 이름 → 내장 메트릭 영문 이름 별칭
fn resolve_metric_alias(name: &str) -> &str {
    match name {
        "함초롬돋움" | "한컴돋움" => "HCR Dotum",
        "돋움" => "Dotum",
        "바탕" | "함초롬바탕" | "한컴바탕" => "HCR Batang",
        "맑은 고딕" => "Malgun Gothic",
        "나눔고딕" => "NanumGothic",
        "나눔명조" => "NanumMyeongjo",
        // 윈도우 시스템 폰트 (가변폭)
        "바탕체" => "BatangChe",
        "굴림" => "Gulim",
        "궁서" => "Gungsuh",
        // 윈도우 시스템 폰트 (고정폭)
        "굴림체" => "GulimChe",
        "돋움체" => "DotumChe",
        "궁서체" => "GungsuhChe",
        _ => name,
    }
}

pub fn find_metric(name: &str, bold: bool, italic: bool) -> Option<MetricMatch> {
    let name = resolve_metric_alias(name);
    // 정확한 매칭 (name + bold + italic)
    if let Some(m) = FONT_METRICS.iter().find(|m| m.name == name && m.bold == bold && m.italic == italic) {
        return Some(MetricMatch { metric: m, bold_fallback: false });
    }
    // bold만 매칭 (italic 무시)
    if let Some(m) = FONT_METRICS.iter().find(|m| m.name == name && m.bold == bold && !m.italic) {
        return Some(MetricMatch { metric: m, bold_fallback: false });
    }
    // Regular 폴백 — bold 요청이었으면 bold_fallback 표시
    FONT_METRICS.iter().find(|m| m.name == name)
        .map(|m| MetricMatch { metric: m, bold_fallback: bold })
}

